module top_module(clk,reset,enable,npc,pc,pcplus);input  [31:0]  npc;
   input          clk,reset,enable;
   output [31:0]  pc,pcplus;

   reg [31:0]     external_counter;

   always @(posedge clk or posedge reset) begin
      if (reset) begin
         external_counter<=32'h00003000;
      end 
      else if(enable) begin
         external_counter<=npc;
      end
   end

   assign pc=external_counter;
   assign pcplus=external_counter+4;

endmodule
